sql:
SELECT owner_id, COUNT(animal_id) AS number_of_animals
FROM owner_animal
GROUP BY owner_id;

SELECT animals.animal_id, animals.animal_name, vaccinations.vaccination_date, vaccinations.vaccination_type
FROM animals
JOIN vaccinations ON animals.animal_id = vaccinations.animal_id;

SELECT animals.*, registrations.registration_date, registrations.registration_type 
FROM animals 
JOIN registrations ON animals.animal_id = registrations.animal_id;

SELECT AVG(animals.weight) AS average_weight
FROM animals
WHERE animals.breed_id = 101;

SELECT animals.animal_name, breeds.breed_name
FROM animals
INNER JOIN breeds ON animals.breed_id = breeds.breed_id;

SELECT DISTINCT o.owner_id
FROM owners AS o
JOIN owner_animal AS oa ON o.owner_id = oa.owner_id;

SELECT owners.owner_name, owners.email, boroughs.borough_name
FROM owners
JOIN boroughs ON owners.borough_id = boroughs.borough_id;
